class Solution:
    def maxTotal(self, nums, s):
        tokens = [i for i, c in enumerate(s) if c == '1']
        if not tokens:
            return 0
        NEG = float('-inf')
        prevStates = None
        for idx in tokens:
            options = [(idx, nums[idx])]
            if idx > 0:
                options.append((idx - 1, nums[idx - 1]))
            newStates = []
            for pos, gain in options:
                if prevStates is None:
                    newStates.append((pos, gain))
                else:
                    best = NEG
                    for ppos, pval in prevStates:
                        cand = pval if pos == ppos else pval + gain
                        if cand > best:
                            best = cand
                    newStates.append((pos, best))
            prevStates = newStates
        return max(v for _, v in prevStates)

