class Solution:
    def maxTotal(self, nums, s: str) -> int:
        n = len(nums)
        if '1' not in s:
            return 0
        NEG = float('-inf')
        prevStayPos = prevMovePos = None
        prevStayVal = prevMoveVal = NEG
        first = True
        for idx in range(n):
            if s[idx] != '1':
                continue
            stayPos = idx
            stayGain = nums[idx]
            movePos = idx - 1 if idx > 0 else None
            moveGain = nums[idx - 1] if idx > 0 else None
            if first:
                newStayVal = stayGain
                newMoveVal = moveGain if movePos is not None else NEG
            else:
                def best_for(pos, gain):
                    best = NEG
                    if prevStayVal != NEG:
                        cand = prevStayVal if pos == prevStayPos else prevStayVal + gain
                        best = max(best, cand)
                    if prevMoveVal != NEG:
                        cand = prevMoveVal if pos == prevMovePos else prevMoveVal + gain
                        best = max(best, cand)
                    return best
                newStayVal = best_for(stayPos, stayGain)
                newMoveVal = best_for(movePos, moveGain) if movePos is not None else NEG
            prevStayPos, prevStayVal = stayPos, newStayVal
            prevMovePos, prevMoveVal = movePos, newMoveVal
            first = False
        return max(prevStayVal, prevMoveVal)

