var maxTotal = function(nums, s) {
    const n = nums.length;
    if (!s.includes('1')) return 0;
    const NEG = -Infinity;
    let prevStayPos = null, prevMovePos = null;
    let prevStayVal = NEG, prevMoveVal = NEG;
    let first = true;
    for (let idx = 0; idx < n; idx++) {
        if (s[idx] !== '1') continue;
        const stayPos = idx;
        const stayGain = nums[idx];
        const movePos = idx > 0 ? idx - 1 : null;
        const moveGain = idx > 0 ? nums[idx - 1] : null;
        let newStayVal, newMoveVal;
        const bestFor = (pos, gain) => {
            let best = NEG;
            if (prevStayVal !== NEG) {
                const cand = (pos === prevStayPos) ? prevStayVal : prevStayVal + gain;
                if (cand > best) best = cand;
            }
            if (prevMoveVal !== NEG) {
                const cand = (pos === prevMovePos) ? prevMoveVal : prevMoveVal + gain;
                if (cand > best) best = cand;
            }
            return best;
        };
        if (first) {
            newStayVal = stayGain;
            newMoveVal = movePos !== null ? moveGain : NEG;
        } else {
            newStayVal = bestFor(stayPos, stayGain);
            newMoveVal = movePos !== null ? bestFor(movePos, moveGain) : NEG;
        }
        prevStayPos = stayPos; prevStayVal = newStayVal;
        prevMovePos = movePos; prevMoveVal = newMoveVal;
        first = false;
    }
    return Math.max(prevStayVal, prevMoveVal);
};
